      FROM pg_constraint con
      JOIN LATERAL unnest(con.conkey) WITH ORDINALITY AS x(attnum, ord) ON true
      JOIN pg_attribute a ON a.attrelid = con.conrelid AND a.attnum = x.attnum
      WHERE con.conrelid = 'public.activities'::regclass AND con.contype = 'p';
    IF pk_cols IS NULL OR NOT ('created_at' = ANY(pk_cols)) THEN
      RAISE EXCEPTION 'activities: primary key (%) must include partition column created_at', pk_cols;
    END IF;

    -- 1b. Guard: no non-PK unique constraints (cannot exist on the partitioned table)
    IF EXISTS (
      SELECT 1 FROM pg_constraint con
      WHERE con.conrelid = 'public.activities'::regclass AND con.contype = 'u'
    ) THEN
      RAISE EXCEPTION 'activities: unique constraints other than the PK cannot be carried onto a table partitioned by created_at';
    END IF;

    -- 2. Capture PK, FKs, non-constraint indexes, and triggers for replay after the
    --    swap (earlier blocks may already have attached triggers, e.g. immutability)
    SELECT pg_get_constraintdef(con.oid) INTO pk_def
      FROM pg_constraint con
      WHERE con.conrelid = 'public.activities'::regclass AND con.contype = 'p';
    SELECT COALESCE(array_agg(format('ALTER TABLE public.activities ADD CONSTRAINT %I %s', con.conname, pg_get_constraintdef(con.oid))), '{}')
      INTO fk_defs
      FROM pg_constraint con
      WHERE con.conrelid = 'public.activities'::regclass AND con.contype = 'f';
    SELECT COALESCE(array_agg(pg_get_indexdef(i.indexrelid)), '{}') INTO idx_defs
      FROM pg_index i
      WHERE i.indrelid = 'public.activities'::regclass
        AND NOT EXISTS (SELECT 1 FROM pg_constraint c WHERE c.conindid = i.indexrelid);
    SELECT COALESCE(array_agg(pg_get_triggerdef(t.oid)), '{}') INTO trg_defs
      FROM pg_trigger t
      WHERE t.tgrelid = 'public.activities'::regclass AND NOT t.tgisinternal;

    -- 3. Move the original aside and create the partitioned table directly under the
    --    final name, so partman child partitions get clean names (activities_p...).
    --    The original's indexes keep their (schema-wide) names — safe, because no index
    --    is created on the new table until the old one is dropped in step 6.
    ALTER TABLE activities RENAME TO activities_old;
    EXECUTE 'CREATE TABLE activities (LIKE activities_old INCLUDING ALL EXCLUDING INDEXES) PARTITION BY RANGE (created_at)';

    -- 4. Register with pg_partman (1 week partitions + DEFAULT) and configure
    --    retention (90 days, drop old partitions)
    PERFORM partman.create_parent(
      p_parent_table => 'public.activities',
      p_control => 'created_at',
      p_interval => '1 week'
    );

    UPDATE partman.part_config SET
      retention = '90 days',
      retention_keep_table = false,
      infinite_time_partitions = true
    WHERE parent_table = 'public.activities';

    -- 5. Copy data (identical column order via LIKE; out-of-range rows go to DEFAULT)
    EXECUTE 'INSERT INTO activities SELECT * FROM activities_old';

    -- 6. Drop old (frees index/constraint names), replay PK + FKs + indexes + triggers
    DROP TABLE activities_old;

    EXECUTE format('ALTER TABLE public.activities ADD %s', pk_def);
    FOREACH ddl IN ARRAY fk_defs LOOP EXECUTE ddl; END LOOP;
    FOREACH ddl IN ARRAY idx_defs LOOP EXECUTE ddl; END LOOP;
    FOREACH ddl IN ARRAY trg_defs LOOP EXECUTE ddl; END LOOP;

    RAISE NOTICE 'activities converted to partitioned';
  END IF;

  -- ==========================================================================
  -- SEEN_BY: convert to partitioned by RANGE (created_at)
  -- ==========================================================================

  IF EXISTS (
    SELECT 1 FROM pg_partitioned_table pt
    JOIN pg_class c ON c.oid = pt.partrelid
    WHERE c.relname = 'seen_by' AND c.relnamespace = 'public'::regnamespace
  ) THEN
    -- Already partitioned: refresh retention config only

    UPDATE partman.part_config SET
      retention = '90 days',
      retention_keep_table = false,
      infinite_time_partitions = true
    WHERE parent_table = 'public.seen_by';
    RAISE NOTICE 'seen_by already partitioned — config updated, skipping conversion';
  ELSE
    -- 1a. Guard: PK must include the partition column
    SELECT array_agg(a.attname::text ORDER BY x.ord) INTO pk_cols
      FROM pg_constraint con
      JOIN LATERAL unnest(con.conkey) WITH ORDINALITY AS x(attnum, ord) ON true
      JOIN pg_attribute a ON a.attrelid = con.conrelid AND a.attnum = x.attnum
      WHERE con.conrelid = 'public.seen_by'::regclass AND con.contype = 'p';
    IF pk_cols IS NULL OR NOT ('created_at' = ANY(pk_cols)) THEN
      RAISE EXCEPTION 'seen_by: primary key (%) must include partition column created_at', pk_cols;
    END IF;

    -- 1b. Guard: no non-PK unique constraints (cannot exist on the partitioned table)
    IF EXISTS (
      SELECT 1 FROM pg_constraint con
      WHERE con.conrelid = 'public.seen_by'::regclass AND con.contype = 'u'
    ) THEN
      RAISE EXCEPTION 'seen_by: unique constraints other than the PK cannot be carried onto a table partitioned by created_at';
    END IF;

    -- 2. Capture PK, FKs, non-constraint indexes, and triggers for replay after the
    --    swap (earlier blocks may already have attached triggers, e.g. immutability)
    SELECT pg_get_constraintdef(con.oid) INTO pk_def
      FROM pg_constraint con
      WHERE con.conrelid = 'public.seen_by'::regclass AND con.contype = 'p';
    SELECT COALESCE(array_agg(format('ALTER TABLE public.seen_by ADD CONSTRAINT %I %s', con.conname, pg_get_constraintdef(con.oid))), '{}')
      INTO fk_defs
      FROM pg_constraint con
      WHERE con.conrelid = 'public.seen_by'::regclass AND con.contype = 'f';
    SELECT COALESCE(array_agg(pg_get_indexdef(i.indexrelid)), '{}') INTO idx_defs
      FROM pg_index i
      WHERE i.indrelid = 'public.seen_by'::regclass
        AND NOT EXISTS (SELECT 1 FROM pg_constraint c WHERE c.conindid = i.indexrelid);
    SELECT COALESCE(array_agg(pg_get_triggerdef(t.oid)), '{}') INTO trg_defs
      FROM pg_trigger t
      WHERE t.tgrelid = 'public.seen_by'::regclass AND NOT t.tgisinternal;

    -- 3. Move the original aside and create the partitioned table directly under the
    --    final name, so partman child partitions get clean names (seen_by_p...).
    --    The original's indexes keep their (schema-wide) names — safe, because no index
    --    is created on the new table until the old one is dropped in step 6.
    ALTER TABLE seen_by RENAME TO seen_by_old;
    EXECUTE 'CREATE TABLE seen_by (LIKE seen_by_old INCLUDING ALL EXCLUDING INDEXES) PARTITION BY RANGE (created_at)';

    -- 4. Register with pg_partman (1 week partitions + DEFAULT) and configure
    --    retention (90 days, drop old partitions)
    PERFORM partman.create_parent(
      p_parent_table => 'public.seen_by',
      p_control => 'created_at',
      p_interval => '1 week'
    );

    UPDATE partman.part_config SET
      retention = '90 days',
      retention_keep_table = false,
      infinite_time_partitions = true
    WHERE parent_table = 'public.seen_by';

    -- 5. Copy data (identical column order via LIKE; out-of-range rows go to DEFAULT)
    EXECUTE 'INSERT INTO seen_by SELECT * FROM seen_by_old';

    -- 6. Drop old (frees index/constraint names), replay PK + FKs + indexes + triggers
    DROP TABLE seen_by_old;

    EXECUTE format('ALTER TABLE public.seen_by ADD %s', pk_def);
    FOREACH ddl IN ARRAY fk_defs LOOP EXECUTE ddl; END LOOP;
    FOREACH ddl IN ARRAY idx_defs LOOP EXECUTE ddl; END LOOP;
    FOREACH ddl IN ARRAY trg_defs LOOP EXECUTE ddl; END LOOP;

    RAISE NOTICE 'seen_by converted to partitioned';
  END IF;

  RAISE NOTICE 'pg_partman setup complete.';
END $$;
--> statement-breakpoint
-- ══════════════════════════════════════════════════════════════════════════
-- [rls_setup] RLS — ownership, FORCE RLS, grants
-- ══════════════════════════════════════════════════════════════════════════
-- RLS (Row-Level Security) Setup
-- Configures FORCE RLS, table ownership, and grants.
-- Policies are defined in Drizzle schema files using pgPolicy().
-- RLS enforces tenant-level isolation only; org-level isolation is application-layer (orgGuard).
-- Gracefully skips if required roles are not yet created.

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_catalog.pg_roles WHERE rolname = 'runtime_role') THEN
    RAISE NOTICE 'Roles not available - skipping RLS setup.';
    RETURN;
  END IF;

  BEGIN
    -- Table ownership and FORCE RLS
    ALTER TABLE attachments OWNER TO admin_role;
    ALTER TABLE yjs_documents OWNER TO admin_role;
    ALTER TABLE activities OWNER TO admin_role;

    ALTER TABLE attachments FORCE ROW LEVEL SECURITY;
    ALTER TABLE yjs_documents FORCE ROW LEVEL SECURITY;

    -- Grants: runtime_role (subject to RLS)
    GRANT SELECT, INSERT, UPDATE, DELETE ON attachments TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON yjs_documents TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON organizations TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON memberships TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON inactive_memberships TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON users TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON sessions TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON user_counters TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON tokens TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON passkeys TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON oauth_accounts TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON totps TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON requests TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON unsubscribe_tokens TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON emails TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON rate_limits TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON channel_counters TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON seen_by TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON product_counters TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON domains TO runtime_role;
    GRANT SELECT, INSERT, UPDATE, DELETE ON tenants TO runtime_role;
    GRANT SELECT ON system_roles TO runtime_role;
    GRANT SELECT ON activities TO runtime_role;

    -- Grants: admin_role (full access; also used by the CDC worker)
    GRANT ALL ON ALL TABLES IN SCHEMA public TO admin_role;
    GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO admin_role;

    -- Grants: pg_catalog usage for JSONB operators
    GRANT USAGE ON SCHEMA pg_catalog TO runtime_role;

    RAISE NOTICE 'RLS setup complete.';
  EXCEPTION WHEN OTHERS THEN
    -- Fail LOUDLY: swallowing this rolled back ownership, FORCE RLS and every grant in
    -- one silent NOTICE — the app then boots with no table grants (every request 403s)
    -- or, worse, without enforced RLS.
    RAISE EXCEPTION 'RLS setup failed: % (SQLSTATE: %)', SQLERRM, SQLSTATE;
  END;
END $$;
