-- [unlogged_setup] UNLOGGED tables
-- ══════════════════════════════════════════════════════════════════════════
-- UNLOGGED Tables Setup
-- Converts ephemeral counter/rate-limit tables to UNLOGGED (skip WAL writes).
-- Idempotent: only alters tables not already UNLOGGED.
-- Gracefully skips if required roles are not yet created.

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_catalog.pg_roles WHERE rolname = 'runtime_role') THEN
    RAISE NOTICE 'Skipping UNLOGGED setup - roles not available.';
    RETURN;
  END IF;

  IF (SELECT relpersistence FROM pg_class WHERE relname = 'rate_limits') != 'u' THEN
    ALTER TABLE rate_limits SET UNLOGGED;
    RAISE NOTICE 'rate_limits set to UNLOGGED';
  END IF;

  IF (SELECT relpersistence FROM pg_class WHERE relname = 'user_counters') != 'u' THEN
    ALTER TABLE user_counters SET UNLOGGED;
    RAISE NOTICE 'user_counters set to UNLOGGED';
  END IF;

  IF (SELECT relpersistence FROM pg_class WHERE relname = 'channel_counters') != 'u' THEN
    ALTER TABLE channel_counters SET UNLOGGED;
    RAISE NOTICE 'channel_counters set to UNLOGGED';
  END IF;

  IF (SELECT relpersistence FROM pg_class WHERE relname = 'product_counters') != 'u' THEN
    ALTER TABLE product_counters SET UNLOGGED;
    RAISE NOTICE 'product_counters set to UNLOGGED';
  END IF;

  RAISE NOTICE 'UNLOGGED setup complete.';
END $$;
--> statement-breakpoint
-- ══════════════════════════════════════════════════════════════════════════
-- [verify_side_effects] Verify — assert end state of all side-effect blocks
-- ══════════════════════════════════════════════════════════════════════════
-- Side-effect verification
-- Asserts the end state of every previous block. A failed assertion aborts (and rolls
-- back) the whole migration instead of shipping a silently degraded database.

DO $$
DECLARE
  missing text[] := '{}';
BEGIN
  -- Functions (created unconditionally by their blocks)
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'base_entity_immutable_keys') THEN
    missing := array_append(missing, 'function:base_entity_immutable_keys'); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'product_entity_immutable_keys') THEN
    missing := array_append(missing, 'function:product_entity_immutable_keys'); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'membership_immutable_keys') THEN
    missing := array_append(missing, 'function:membership_immutable_keys'); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'inactive_membership_immutable_keys') THEN
    missing := array_append(missing, 'function:inactive_membership_immutable_keys'); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'append_only_immutable_row') THEN
    missing := array_append(missing, 'function:append_only_immutable_row'); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'admin_only_write_row') THEN
    missing := array_append(missing, 'function:admin_only_write_row'); END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'apply_count_deltas') THEN
    missing := array_append(missing, 'function:apply_count_deltas'); END IF;

  -- Immutability triggers + RLS + grants + UNLOGGED (same precondition as their blocks: roles exist)
  IF EXISTS (SELECT 1 FROM pg_catalog.pg_roles WHERE rolname = 'runtime_role') THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
      WHERE c.relnamespace = 'public'::regnamespace AND c.relname = 'organizations'
        AND t.tgname = 'organizations_immutable_keys_trigger' AND NOT t.tgisinternal
    ) THEN missing := array_append(missing, 'trigger:organizations_immutable_keys_trigger'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
      WHERE c.relnamespace = 'public'::regnamespace AND c.relname = 'attachments'
        AND t.tgname = 'attachments_immutable_keys_trigger' AND NOT t.tgisinternal
    ) THEN missing := array_append(missing, 'trigger:attachments_immutable_keys_trigger'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
      WHERE c.relnamespace = 'public'::regnamespace AND c.relname = 'memberships'
        AND t.tgname = 'memberships_immutable_keys_trigger' AND NOT t.tgisinternal
    ) THEN missing := array_append(missing, 'trigger:memberships_immutable_keys_trigger'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
      WHERE c.relnamespace = 'public'::regnamespace AND c.relname = 'inactive_memberships'
        AND t.tgname = 'inactive_memberships_immutable_keys_trigger' AND NOT t.tgisinternal
    ) THEN missing := array_append(missing, 'trigger:inactive_memberships_immutable_keys_trigger'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
      WHERE c.relnamespace = 'public'::regnamespace AND c.relname = 'activities'
        AND t.tgname = 'activities_immutable_keys_trigger' AND NOT t.tgisinternal
    ) THEN missing := array_append(missing, 'trigger:activities_immutable_keys_trigger'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_trigger t JOIN pg_class c ON c.oid = t.tgrelid
      WHERE c.relnamespace = 'public'::regnamespace AND c.relname = 'system_roles'
        AND t.tgname = 'system_roles_admin_only_write_trigger' AND NOT t.tgisinternal
    ) THEN missing := array_append(missing, 'trigger:system_roles_admin_only_write_trigger'); END IF;

    IF NOT EXISTS (
      SELECT 1 FROM pg_class WHERE relname = 'attachments' AND relnamespace = 'public'::regnamespace
        AND relrowsecurity AND relforcerowsecurity
    ) THEN missing := array_append(missing, 'force-rls:attachments'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_class WHERE relname = 'yjs_documents' AND relnamespace = 'public'::regnamespace
        AND relrowsecurity AND relforcerowsecurity
    ) THEN missing := array_append(missing, 'force-rls:yjs_documents'); END IF;

    IF NOT has_table_privilege('runtime_role', 'public.attachments', 'SELECT') THEN
      missing := array_append(missing, 'grant:attachments'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.yjs_documents', 'SELECT') THEN
      missing := array_append(missing, 'grant:yjs_documents'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.organizations', 'SELECT') THEN
      missing := array_append(missing, 'grant:organizations'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.memberships', 'SELECT') THEN
      missing := array_append(missing, 'grant:memberships'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.inactive_memberships', 'SELECT') THEN
      missing := array_append(missing, 'grant:inactive_memberships'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.users', 'SELECT') THEN
      missing := array_append(missing, 'grant:users'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.sessions', 'SELECT') THEN
      missing := array_append(missing, 'grant:sessions'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.user_counters', 'SELECT') THEN
      missing := array_append(missing, 'grant:user_counters'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.tokens', 'SELECT') THEN
      missing := array_append(missing, 'grant:tokens'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.passkeys', 'SELECT') THEN
      missing := array_append(missing, 'grant:passkeys'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.oauth_accounts', 'SELECT') THEN
      missing := array_append(missing, 'grant:oauth_accounts'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.totps', 'SELECT') THEN
      missing := array_append(missing, 'grant:totps'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.requests', 'SELECT') THEN
      missing := array_append(missing, 'grant:requests'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.unsubscribe_tokens', 'SELECT') THEN
      missing := array_append(missing, 'grant:unsubscribe_tokens'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.emails', 'SELECT') THEN
      missing := array_append(missing, 'grant:emails'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.rate_limits', 'SELECT') THEN
      missing := array_append(missing, 'grant:rate_limits'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.channel_counters', 'SELECT') THEN
      missing := array_append(missing, 'grant:channel_counters'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.seen_by', 'SELECT') THEN
      missing := array_append(missing, 'grant:seen_by'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.product_counters', 'SELECT') THEN
      missing := array_append(missing, 'grant:product_counters'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.domains', 'SELECT') THEN
      missing := array_append(missing, 'grant:domains'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.tenants', 'SELECT') THEN
      missing := array_append(missing, 'grant:tenants'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.system_roles', 'SELECT') THEN
      missing := array_append(missing, 'grant:system_roles'); END IF;
    IF NOT has_table_privilege('runtime_role', 'public.activities', 'SELECT') THEN
      missing := array_append(missing, 'grant:activities'); END IF;

    IF (SELECT relpersistence FROM pg_class WHERE relname = 'rate_limits' AND relnamespace = 'public'::regnamespace) IS DISTINCT FROM 'u' THEN
      missing := array_append(missing, 'unlogged:rate_limits'); END IF;
    IF (SELECT relpersistence FROM pg_class WHERE relname = 'user_counters' AND relnamespace = 'public'::regnamespace) IS DISTINCT FROM 'u' THEN
      missing := array_append(missing, 'unlogged:user_counters'); END IF;
    IF (SELECT relpersistence FROM pg_class WHERE relname = 'channel_counters' AND relnamespace = 'public'::regnamespace) IS DISTINCT FROM 'u' THEN
      missing := array_append(missing, 'unlogged:channel_counters'); END IF;
    IF (SELECT relpersistence FROM pg_class WHERE relname = 'product_counters' AND relnamespace = 'public'::regnamespace) IS DISTINCT FROM 'u' THEN
      missing := array_append(missing, 'unlogged:product_counters'); END IF;
  ELSE
    RAISE NOTICE 'verify: roles not available - skipping trigger/RLS/grant/unlogged assertions.';
  END IF;

  -- Partitioning (same precondition as the partman block: extension installed)
  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_partman') THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_partitioned_table pt JOIN pg_class c ON c.oid = pt.partrelid
      WHERE c.relname = 'sessions' AND c.relnamespace = 'public'::regnamespace
    ) THEN missing := array_append(missing, 'partitioned:sessions'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_partitioned_table pt JOIN pg_class c ON c.oid = pt.partrelid
      WHERE c.relname = 'tokens' AND c.relnamespace = 'public'::regnamespace
    ) THEN missing := array_append(missing, 'partitioned:tokens'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_partitioned_table pt JOIN pg_class c ON c.oid = pt.partrelid
      WHERE c.relname = 'unsubscribe_tokens' AND c.relnamespace = 'public'::regnamespace
    ) THEN missing := array_append(missing, 'partitioned:unsubscribe_tokens'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_partitioned_table pt JOIN pg_class c ON c.oid = pt.partrelid
      WHERE c.relname = 'activities' AND c.relnamespace = 'public'::regnamespace
    ) THEN missing := array_append(missing, 'partitioned:activities'); END IF;
    IF NOT EXISTS (
      SELECT 1 FROM pg_partitioned_table pt JOIN pg_class c ON c.oid = pt.partrelid
      WHERE c.relname = 'seen_by' AND c.relnamespace = 'public'::regnamespace
    ) THEN missing := array_append(missing, 'partitioned:seen_by'); END IF;
  ELSE
    RAISE NOTICE 'verify: pg_partman not installed - skipping partition assertions.';
  END IF;

  -- CDC publication (8 tracked tables)
  IF NOT EXISTS (SELECT 1 FROM pg_publication WHERE pubname = 'cdc_pub') THEN
    missing := array_append(missing, 'publication:cdc_pub');
  ELSIF (SELECT count(DISTINCT tablename) FROM pg_publication_tables WHERE pubname = 'cdc_pub') <> 8 THEN
    missing := array_append(missing, 'publication-tables:cdc_pub');
  END IF;

  IF array_length(missing, 1) > 0 THEN
    RAISE EXCEPTION 'DB side-effect verification failed — missing: %', array_to_string(missing, ', ');
  END IF;

  RAISE NOTICE 'Side-effect verification passed.';
END $$;
